mapper.select:
SELECT lr.id, lr.staff_id, s.sname as staff_name, lr.leave_type, lr.days, lr.start_date, lr.end_date, lr.status, lr.hr_id, hr.sname as approver_name, lr.approval_time, lr.reason, lr.create_time, d.dname as department_name, j.jname as job_name FROM leave_request lr LEFT JOIN staffs s ON lr.staff_id = s.id LEFT JOIN staffs hr ON lr.hr_id = hr.id LEFT JOIN departments d ON s.dept_id = d.id LEFT JOIN jobs j ON s.job_id = j.id
AND lr.staff_id = #{staffId}
AND s.dept_id = #{deptId}
AND lr.status = #{status}
AND lr.leave_type = #{leaveType}
AND lr.start_date >= #{startDate}
AND lr.end_date <= #{endDate}
AND DATE_FORMAT(lr.start_date, '%Y-%m') = #{month}
ORDER BY lr.create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM leave_request lr
LEFT JOIN staffs s ON lr.staff_id = s.id
LEFT JOIN departments d ON s.dept_id = d.id


        AND lr.staff_id = #{staffId}


        AND s.dept_id = #{deptId}


        AND lr.status = #{status}


        AND lr.leave_type = #{leaveType}


        AND lr.start_date >= #{startDate}


        AND lr.end_date <= #{endDate}


        AND DATE_FORMAT(lr.start_date, '%Y-%m') = #{month}

SELECT COUNT(*) as totalApplications, SUM(CASE WHEN status = '待审批' THEN 1 ELSE 0 END) as pendingCount, SUM(CASE WHEN status = '已批准' THEN 1 ELSE 0 END) as approvedCount, SUM(CASE WHEN status = '已拒绝' THEN 1 ELSE 0 END) as rejectedCount, SUM(CASE WHEN status = '已批准' THEN days ELSE 0 END) as totalLeaveDays, COUNT(DISTINCT staff_id) as totalStaff FROM leave_request lr LEFT JOIN staffs s ON lr.staff_id = s.id
AND DATE_FORMAT(lr.start_date, '%Y-%m') = #{month}
AND s.dept_id = #{deptId}

SELECT COALESCE(SUM(days), 0)
FROM leave_request
WHERE staff_id = #{staffId}
  AND status = '已批准'
  AND DATE_FORMAT(start_date, '%Y-%m') = #{month}

